import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

const PALETTE = {
  CLEMENTINA: "#FF4201",
  SKYNE: "#199ECA",
  IVRAE: "#F6EEE3",
  NEGRO: "#000000",
  VERDE: "#166D3B", // Original green
  WHITE: "#FFFFFF",
  INPUT_BORDER: "#D0D0D0",
  SHADOW_CONTOUR_COLOR: "rgba(0, 0, 0, 0.4)",
};

const ICON_SVG_SIZE = "40px";
const ICON_CONTAINER_PADDING = "10px";
const SMALL_ICON_SVG_SIZE = "22px"; // For the eye icon

const UserIcon = ({ color, size = ICON_SVG_SIZE }) => (
  <svg
    viewBox="0 0 24 24"
    style={{ width: size, height: size, fill: color, display: "block" }}
  >
    <path d="M12 12c2.76 0 5-2.24 5-5S14.76 2 12 2 7 4.24 7 7s2.24 5 5 5zm0 2c-3.33 0-10 1.67-10 5v3h20v-3c0-3.33-6.67-5-10-5z" />
  </svg>
);

const EyeIconShow = ({ color, size = SMALL_ICON_SVG_SIZE }) => (
  <svg
    viewBox="0 0 24 24"
    style={{ width: size, height: size, fill: color, display: "block" }}
  >
    <path d="M12 4.5C7 4.5 2.73 7.61 1 12c1.73 4.39 6 7.5 11 7.5s9.27-3.11 11-7.5c-1.73-4.39-6-7.5-11-7.5zM12 17c-2.76 0-5-2.24-5-5s2.24-5 5-5 5 2.24 5 5-2.24 5-5 5zm0-8c-1.66 0-3 1.34-3 3s1.34 3 3 3 3-1.34 3-3-1.34-3-3-3z" />
  </svg>
);

const EyeIconHide = ({ color, size = SMALL_ICON_SVG_SIZE }) => (
  <svg
    viewBox="0 0 24 24"
    style={{ width: size, height: size, fill: color, display: "block" }}
  >
    <path d="M12 7c2.76 0 5 2.24 5 5 0 .65-.13 1.26-.36 1.83l2.92 2.92c1.51-1.26 2.7-2.89 3.44-4.75C21.27 7.61 17 4.5 12 4.5c-1.6 0-3.14.35-4.54.96l1.56 1.56C9.74 7.13 10.85 7 12 7zm-1.07 5.53l2.81 2.81c-.71.15-1.44.26-2.19.26-2.76 0-5-2.24-5-5 0-.75.11-1.48.26-2.19l2.81 2.81c.11.7.42 1.34.81 1.81zM2.71 3.27L1.44 4.54l2.02 2.02C2.03 7.95 1.16 9.77 1 12c1.73 4.39 6 7.5 11 7.5 1.55 0 3.03-.3 4.38-.84l1.53 1.53 1.27-1.27L2.71 3.27z" />
  </svg>
);

const InicioSesion = ({ onLogin, onClose }) => {
  const [usuario, setUsuario] = useState("");
  const [contrasenia, setContrasenia] = useState("");
  const [showPassword, setShowPassword] = useState(false); // State for password visibility
  const [loading, setLoading] = useState(false);
  const [mensaje, setMensaje] = useState(null);
  const [isVisible, setIsVisible] = useState(true);

  const inputVariants = {
    focus: {
      scale: 1.02,
      boxShadow: `0 0 0 2px ${PALETTE.CLEMENTINA}`,
      transition: { duration: 0.3 },
    },
  };
  const buttonVariants = {
    hover: { scale: 1.05, transition: { duration: 0.2 } },
  };

  const backdropVariants = {
    hidden: { opacity: 0 },
    visible: { opacity: 1, transition: { duration: 0.3 } },
    exit: { opacity: 0, transition: { duration: 0.3 } },
  };
  const modalVariants = {
    hidden: { y: -50, opacity: 0 },
    visible: { y: 0, opacity: 1, transition: { type: "spring", stiffness: 120, damping: 20 } },
    exit: { y: -50, opacity: 0, transition: { duration: 0.3 } },
  };
  const iconVariants = {
    hidden: { scale: 0 },
    visible: { scale: 1, transition: { delay: 0.4, type: "spring", stiffness: 150 } },
    exit: { scale: 0, transition: { duration: 0.2 } },
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMensaje(null);

    if (!usuario || !contrasenia) {
      setMensaje("Por favor, rellena todos los campos");
      return;
    }

    setLoading(true);
    try {
      const res = await fetch("http://localhost:3000/usuarios/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ usuario, contrasenia }),
      });
      const data = await res.json();

      if (res.ok && data.encontrado === 1) {
        setMensaje("Iniciaste sesión correctamente");
        onLogin(data.usuario);
        setTimeout(() => {
          setIsVisible(false);
          if (onClose) onClose();
        }, 1500);
      } else {
        setMensaje(data.mensaje || "Credenciales incorrectas");
      }
    } catch {
      setMensaje("Error de conexión con el servidor");
    } finally {
      setLoading(false);
    }
  };

  const handleClose = () => {
    setIsVisible(false);
    // Call onClose passed from parent only after exit animation completes
    // AnimatePresence's onExitComplete handles this.
  };

  const onExitComplete = () => {
    if (onClose) onClose();
  }

  const inputBaseStyle = {
    width: "100%",
    padding: "12px 15px",
    fontSize: "18px",
    border: `1px solid ${PALETTE.INPUT_BORDER}`,
    borderRadius: "8px",
    backgroundColor: PALETTE.WHITE,
    marginBottom: "18px",
    textAlign: "center",
    color: PALETTE.NEGRO,
    fontFamily: "'Caveat', cursive",
    boxSizing: "border-box",
  };

  const passwordInputStyle = {
    ...inputBaseStyle,
    paddingRight: "45px", // Make space for the icon
  };

  const iconContainerStyle = {
    position: "absolute",
    top: "-30px", // Half of the icon container height (approx 60px with padding)
    left: "50%", // Centered
    transform: "translateX(-50%)",
    backgroundColor: PALETTE.IVRAE,
    borderRadius: "50%",
    padding: ICON_CONTAINER_PADDING,
    boxShadow: "0px -3px 6px rgba(0, 0, 0, 0.1)",
    zIndex: 1,
  };

  const modalStyle = {
    position: "relative",
    backgroundColor: PALETTE.IVRAE,
    borderRadius: "27px",
    width: "500px", // Slightly larger modal
    padding: "45px 30px 30px",
    textAlign: "center",
    fontFamily: "'Poppins', sans-serif",
    boxShadow: `0 0 0 10px ${PALETTE.SHADOW_CONTOUR_COLOR}`,
  };

  const mensajeStyle = {
    marginBottom: "10px",
    fontWeight: "bold",
    color: mensaje === "Iniciaste sesión correctamente" ? PALETTE.VERDE : PALETTE.CLEMENTINA,
    fontFamily: "'Poppins', sans-serif", // Ensure Poppins for message
    fontSize: "15px",
  };

  const passwordInputContainerStyle = {
    position: "relative",
    width: "100%",
    marginBottom: "18px", // Same as inputBaseStyle.marginBottom
  };

  const passwordToggleButtonStyle = {
    position: "absolute",
    top: "50%",
    right: "15px",
    transform: "translateY(-50%)",
    background: "none",
    border: "none",
    cursor: "pointer",
    padding: "0",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    color: PALETTE.NEGRO, // Or a less prominent color like PALETTE.INPUT_BORDER
  };


  return (
    <AnimatePresence onExitComplete={onExitComplete}>
      {isVisible && (
        <motion.div
          key="backdrop"
          variants={backdropVariants}
          initial="hidden"
          animate="visible"
          exit="exit"
          style={{
            position: "fixed",
            top: 0,
            left: 0,
            width: "100vw",
            height: "100vh",
            backgroundColor: "rgba(0,0,0,0.65)",
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            zIndex: 9999,
          }}
        >
          <motion.div
            key="modal"
            variants={modalVariants}
            initial="hidden"
            animate="visible"
            exit="exit"
            style={modalStyle}
          >
            <motion.div
              variants={iconVariants}
              initial="hidden"
              animate="visible"
              exit="exit"
              style={iconContainerStyle}
            >
              <UserIcon color={PALETTE.NEGRO} />
            </motion.div>

            <motion.button
              onClick={handleClose}
              whileHover={{ scale: 1.2 }}
              style={{
                position: "absolute",
                top: "8px",
                right: "20px",
                background: "none",
                border: "none",
                fontSize: "45px",
                cursor: "pointer",
                color: PALETTE.NEGRO,
                lineHeight: 1,
                padding: 0,
              }}
            >
              &times;
            </motion.button>

            <h2
              style={{
                margin: "15px 0", // Adjusted margin to give space from icon
                paddingTop: "10px", // Ensure title is below the icon visually
                fontSize: "18px",
                fontWeight: 600,
                color: PALETTE.NEGRO,
                textTransform: "uppercase",
                letterSpacing: "1px",
                fontFamily: "'Poppins', sans-serif",
              }}
            >
              Inicio de Sesión
            </h2>

            {mensaje && <p style={mensajeStyle}>{mensaje}</p>}

            <form onSubmit={handleSubmit}>
              <motion.input
                type="text"
                placeholder="USUARIO"
                value={usuario}
                onChange={(e) => setUsuario(e.target.value)}
                variants={inputVariants}
                whileFocus="focus"
                style={inputBaseStyle}
              />
              <div style={passwordInputContainerStyle}>
                <motion.input
                  type={showPassword ? "text" : "password"}
                  placeholder="CONTRASEÑA"
                  value={contrasenia}
                  onChange={(e) => setContrasenia(e.target.value)}
                  variants={inputVariants}
                  whileFocus="focus"
                  style={passwordInputStyle} // Use the style with padding for the icon
                />
                <motion.button
                  type="button" // Important: type="button" to prevent form submission
                  onClick={() => setShowPassword(!showPassword)}
                  style={passwordToggleButtonStyle}
                  whileHover={{ scale: 1.1 }}
                  title={showPassword ? "Ocultar contraseña" : "Mostrar contraseña"}
                >
                  {showPassword ? <EyeIconHide color={PALETTE.NEGRO} /> : <EyeIconShow color={PALETTE.NEGRO} />}
                </motion.button>
              </div>
              <motion.button
                type="submit"
                disabled={loading}
                variants={buttonVariants}
                whileHover="hover"
                style={{
                  width: "100%",
                  padding: "12px",
                  fontSize: "15px",
                  fontWeight: 500,
                  border: "none",
                  borderRadius: "8px",
                  backgroundColor: "rgba(22, 109, 59, 0.75)", // PALETTE.VERDE with reduced opacity
                  color: PALETTE.WHITE,
                  cursor: loading ? "not-allowed" : "pointer",
                  textTransform: "uppercase",
                  opacity: loading ? 0.75 : 1,
                  fontFamily: "'Poppins', sans-serif",
                }}
              >
                {loading ? "Iniciando..." : "ENVIAR"}
              </motion.button>
            </form>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

export default InicioSesion;
